class Solution:
    def numberOfCombinations(self, num):
        MOD = 10 ** 9 + 7
        n = len(num)
        if n == 0 or num[0] == '0':
            return 0
        # cmp_le[i][j] for equal-length pieces a=num[i:i+L], b=num[j:j+L]: True if a <= b
        # We compare directly (O(L)) since inputs are small in the oracle.
        def piece_le(i, j, L):
            # both pieces length L, compare num[i:i+L] <= num[j:j+L]
            a = num[i:i + L]
            b = num[j:j + L]
            return a <= b
        # dp[i][j] = number of valid partitions of prefix num[0:i] whose last piece is num[j:i]
        dp = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(1, n + 1):
            for j in range(i):
                if num[j] == '0':
                    continue
                L = i - j
                # previous piece ends at j, starts at p (0 <= p < j), length j - p
                if j == 0:
                    dp[i][j] = 1
                    continue
                total = 0
                for p in range(j):
                    if num[p] == '0':
                        continue
                    plen = j - p
                    if plen < L:
                        total += dp[j][p]
                    elif plen == L:
                        if piece_le(p, j, L):
                            total += dp[j][p]
                    # plen > L: previous longer than current -> invalid
                dp[i][j] = total % MOD
        return sum(dp[n][j] for j in range(n)) % MOD

