class Solution:
    def numberOfCombinations(self, num):
        MOD = 10 ** 9 + 7
        n = len(num)
        if n == 0 or num[0] == '0':
            return 0
        # lcp[i][j] = length of longest common prefix of suffixes starting at i and j
        lcp = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if num[i] == num[j]:
                    lcp[i][j] = lcp[i + 1][j + 1] + 1
        def le(i, j, L):
            # is num[i:i+L] <= num[j:j+L]?  (equal length)
            c = lcp[i][j]
            if c >= L:
                return True
            return num[i + c] < num[j + c]
        # dp[i][j] = #partitions of num[0:i] whose last piece is num[j:i]
        # pref[i][j] = sum_{p<=j} dp[i][p]
        dp = [[0] * (n + 1) for _ in range(n + 1)]
        pref = [[0] * (n + 2) for _ in range(n + 1)]
        for i in range(1, n + 1):
            for j in range(i):
                if num[j] == '0':
                    dp[i][j] = 0
                else:
                    L = i - j
                    if j == 0:
                        dp[i][j] = 1
                    else:
                        # previous piece num[p:j], length j-p; need <= current
                        # candidates with prev length < L: p in (j-L, j) i.e. p > j-L
                        # but also p >= 0
                        lo = max(0, j - L + 1)  # prev length j-p <= L-1  => p >= j-L+1
                        # sum dp[j][p] for p in [lo, j-1] (strictly shorter)
                        val = (pref[j][j - 1] - (pref[j][lo - 1] if lo - 1 >= 0 else 0)) % MOD if j - 1 >= lo else 0
                        # equal length case: prev length == L => p = j - L, if >= 0
                        p_eq = j - L
                        if p_eq >= 0 and num[p_eq] != '0':
                            if le(p_eq, j, L):
                                val = (val + dp[j][p_eq]) % MOD
                        dp[i][j] = val % MOD
                # update prefix for row i
                pref[i][j] = ((pref[i][j - 1] if j - 1 >= 0 else 0) + dp[i][j]) % MOD
            # fill remaining prefix entries (j from i..n) flat
            for j in range(i, n + 1):
                pref[i][j] = pref[i][i - 1]
        return sum(dp[n][j] for j in range(n)) % MOD

