var numberOfCombinations = function(num) {
    const MOD = 1000000007n;
    const n = num.length;
    if (n === 0 || num[0] === '0') return 0;
    const lcp = Array.from({length: n + 1}, () => new Int32Array(n + 1));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = n - 1; j >= 0; j--) {
            if (num[i] === num[j]) lcp[i][j] = lcp[i + 1][j + 1] + 1;
        }
    }
    const le = (i, j, L) => {
        const c = lcp[i][j];
        if (c >= L) return true;
        return num[i + c] < num[j + c];
    };
    const dp = Array.from({length: n + 1}, () => new Array(n + 1).fill(0n));
    const pref = Array.from({length: n + 1}, () => new Array(n + 2).fill(0n));
    for (let i = 1; i <= n; i++) {
        for (let j = 0; j < i; j++) {
            if (num[j] === '0') {
                dp[i][j] = 0n;
            } else {
                const L = i - j;
                if (j === 0) {
                    dp[i][j] = 1n;
                } else {
                    const lo = Math.max(0, j - L + 1);
                    let val = 0n;
                    if (j - 1 >= lo) {
                        const hi = pref[j][j - 1];
                        const sub = lo - 1 >= 0 ? pref[j][lo - 1] : 0n;
                        val = ((hi - sub) % MOD + MOD) % MOD;
                    }
                    const pEq = j - L;
                    if (pEq >= 0 && num[pEq] !== '0') {
                        if (le(pEq, j, L)) val = (val + dp[j][pEq]) % MOD;
                    }
                    dp[i][j] = val % MOD;
                }
            }
            pref[i][j] = (((j - 1 >= 0 ? pref[i][j - 1] : 0n) + dp[i][j]) % MOD);
        }
        for (let j = i; j <= n; j++) pref[i][j] = pref[i][i - 1];
    }
    let ans = 0n;
    for (let j = 0; j < n; j++) ans = (ans + dp[n][j]) % MOD;
    return Number(ans);
};
